    assert(vputils::isSingleScalar(Op) && "Operand not found in Def2LaneDefs");
    NewOps.push_back(Op);
  }

  VPReplicateRecipe *New = Builder.createReplicateRecipe(
      RepR->getUnderlyingInstr(), NewOps, /*IsSingleScalar=*/true);
  New->transferFlags(*RepR);
  New->insertBefore(RepR);
  return New;
